import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: URL {
        switch self {
        case .development:
            return URL(string: "https://api.example.com/dev")!
        case .staging:
            return URL(string: "https://api.example.com/stg")!
        case .production:
            return URL(string: "https://api.example.com/prod")!
        }
    }
}

class NetworkingManager {
    
    private let environment: Environment
    private let session = URLSession.shared
    
    init(environment: Environment) {
        self.environment = environment
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Result<String, Error>) -> Void) {
        let url = environment.baseURL.appendingPathComponent("auth")
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        
        let authData = "\(username):\(password)".data(using: .utf8)!
        let base64EncodedCredentials = authData.base64EncodedString()
        
        request.addValue("Basic \(base64EncodedCredentials)", forHTTPHeaderField: "Authorization")
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
                completion(.failure(NSError(domain: "HTTPError", code: 401, userInfo: [NSLocalizedDescriptionKey: "Authentication failed"])))
                return
            }
            
            if let data = data {
                // Assuming the response is a JSON object with an "accessToken" key
                do {
                    if let json = try JSONSerialization.jsonObject(with: data, options: []) as? [String: Any],
                       let accessToken = json["accessToken"] as? String {
                        completion(.success(accessToken))
                    } else {
                        completion(.failure(NSError(domain: "InvalidResponse", code: 400, userInfo: [NSLocalizedDescriptionKey: "Invalid response format"])))
                    }
                } catch {
                    completion(.failure(error))
                }
            } else {
                completion(.failure(NSError(domain: "NoData", code: 204, userInfo: [NSLocalizedDescriptionKey: "No data received"])))
            }
        }
        
        task.resume()
    }
    
    func fetchUserData(accessToken: String, completion: @escaping (Result<[String: Any], Error>) -> Void) {
        let url = environment.baseURL.appendingPathComponent("user")
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        request.addValue("Bearer \(accessToken)", forHTTPHeaderField: "Authorization")
        
        let task = session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, (200...299).contains(httpResponse.statusCode) else {
                completion(.failure(NSError(domain: "HTTPError", code: httpResponse.statusCode ?? 500, userInfo: [NSLocalizedDescriptionKey: "Invalid HTTP status code"])))
                return
            }
            
            if let data = data {
                do {
                    if let json = try JSONSerialization.jsonObject(with: data, options: []) as? [String: Any] {
                        completion(.success(json))
                    } else {
                        completion(.failure(NSError(domain: "InvalidResponse", code: 400, userInfo: [NSLocalizedDescriptionKey: "Invalid response format"])))
                    }
                } catch {
                    completion(.failure(error))
                }
            } else {
                completion(.failure(NSError(domain: "NoData", code: 204, userInfo: [NSLocalizedDescriptionKey: "No data received"])))
            }
        }
        
        task.resume()
    }
}

// Example usage:
let networkingManager = NetworkingManager(environment: .development)

networkingManager.authenticate(username: "user", password: "password") { result in
    switch result {
    case .success(let token):
        print("Authentication successful. Token: \(token)")
        
        networkingManager.fetchUserData(accessToken: token) { userDataResult in
